import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {}
for col, pol in policy.items():
    n = int(df[col].isna().sum())
    if pol == "required" and n > 0:
        viol[col] = n
print(viol)

import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {c: int(df[c].isna().sum()) for c, p in policy.items() if p == "required" and df[c].isna().any()}
print("fail" if viol else "pass")

import pandas as pd
df = pd.DataFrame({"cliente_id": ["C001"], "region": ["Lima"]})
row = df[df.cliente_id == "C001"]
if int(row.duplicated(keep=False).sum()) > 0:
    label = "exact"
elif row["region"].nunique() > 1:
    label = "conflict"
else:
    label = "clean"
print(label)
